import{_ as t,o,c as d,ag as a}from"./chunks/framework.OsDJF_Ea.js";const p=JSON.parse('{"title":"Databricks Asset Bundle Support","description":"","frontmatter":{},"headers":[],"relativePath":"bundle.md","filePath":"bundle.md"}'),c={name:"bundle.md"};function s(r,e,n,i,l,h){return o(),d("div",null,[...e[0]||(e[0]=[a(`<h1 id="databricks-asset-bundle-support" tabindex="-1">Databricks Asset Bundle Support <a class="header-anchor" href="#databricks-asset-bundle-support" aria-label="Permalink to &quot;Databricks Asset Bundle Support&quot;">​</a></h1><p>CatalystOps detects <code>databricks.yml</code> in your workspace root and provides a sidebar panel, inline YAML linting, and a connection wizard shortcut for Databricks Asset Bundle (DAB) projects.</p><h2 id="bundle-tasks-panel" tabindex="-1">Bundle Tasks Panel <a class="header-anchor" href="#bundle-tasks-panel" aria-label="Permalink to &quot;Bundle Tasks Panel&quot;">​</a></h2><p>Open the <strong>Bundle Tasks</strong> view in the CatalystOps sidebar. It lists every task found across <code>databricks.yml</code> and all files referenced by <code>include:</code> patterns:</p><ul><li><code>spark_python_task</code> entries show the Python file path</li><li><code>notebook_task</code> entries with local paths show the notebook path</li><li>Click any task to open its source file in the editor</li><li>Use the inline <strong>Analyze</strong> button to run a dry-run plan analysis on that task&#39;s script</li></ul><p>The panel refreshes automatically whenever <code>databricks.yml</code> or any included resource YAML changes.</p><h2 id="yaml-linting" tabindex="-1">YAML Linting <a class="header-anchor" href="#yaml-linting" aria-label="Permalink to &quot;YAML Linting&quot;">​</a></h2><p>CatalystOps validates bundle YAML inline as you type. Diagnostics appear as underlines directly in the editor.</p><h3 id="key-structure-checks" tabindex="-1">Key / Structure Checks <a class="header-anchor" href="#key-structure-checks" aria-label="Permalink to &quot;Key / Structure Checks&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Rule</th><th>Severity</th></tr></thead><tbody><tr><td>Unknown top-level keys (only <code>bundle</code>, <code>include</code>, <code>variables</code>, <code>resources</code>, <code>targets</code>, etc.)</td><td>Warning</td></tr><tr><td>Unknown resource types under <code>resources:</code></td><td>Warning</td></tr><tr><td>Include patterns that match no files</td><td>Warning</td></tr></tbody></table><h3 id="enum-validation" tabindex="-1">Enum Validation <a class="header-anchor" href="#enum-validation" aria-label="Permalink to &quot;Enum Validation&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Field</th><th>Valid Values</th></tr></thead><tbody><tr><td><code>data_security_mode</code></td><td><code>SINGLE_USER</code>, <code>USER_ISOLATION</code>, <code>NONE</code>, <code>LEGACY_*</code></td></tr><tr><td><code>runtime_engine</code></td><td><code>PHOTON</code>, <code>STANDARD</code></td></tr><tr><td><code>pause_status</code></td><td><code>PAUSED</code>, <code>UNPAUSED</code></td></tr><tr><td><code>target.mode</code></td><td><code>development</code>, <code>production</code></td></tr><tr><td><code>run_if</code> (task)</td><td><code>ALL_SUCCESS</code>, <code>ALL_DONE</code>, <code>NONE_FAILED</code>, <code>AT_LEAST_ONE_SUCCESS</code>, <code>ALL_FAILED</code>, <code>AT_LEAST_ONE_FAILED</code></td></tr><tr><td><code>trigger.periodic.unit</code></td><td><code>HOURS</code>, <code>DAYS</code>, <code>WEEKS</code></td></tr><tr><td><code>health.rules[].metric</code></td><td><code>RUN_DURATION_SECONDS</code>, <code>STREAMING_BACKLOG_SECONDS</code>, <code>STREAMING_BACKLOG_RECORDS</code></td></tr><tr><td><code>health.rules[].op</code></td><td><code>GREATER_THAN</code></td></tr><tr><td>Permission <code>level</code> (job)</td><td><code>CAN_VIEW</code>, <code>CAN_MANAGE_RUN</code>, <code>CAN_MANAGE</code></td></tr><tr><td>Permission <code>level</code> (dashboard/alert)</td><td><code>CAN_READ</code>, <code>CAN_RUN</code>, <code>CAN_EDIT</code>, <code>CAN_MANAGE</code></td></tr></tbody></table><h3 id="alert-v2-schema-checks" tabindex="-1">Alert v2 Schema Checks <a class="header-anchor" href="#alert-v2-schema-checks" aria-label="Permalink to &quot;Alert v2 Schema Checks&quot;">​</a></h3><p>The Databricks Alert v2 API schema differs from other resources. CatalystOps catches these common mistakes:</p><table tabindex="0"><thead><tr><th>Mistake</th><th>Correct form</th></tr></thead><tbody><tr><td><code>condition:</code> key</td><td>Use <code>evaluation:</code></td></tr><tr><td><code>subscriptions:</code> at alert level</td><td>Move under <code>evaluation.notification.subscriptions</code></td></tr><tr><td><code>schedule.cron_schedule:</code></td><td>Use <code>schedule.quartz_cron_schedule:</code></td></tr><tr><td>Missing <code>schedule.pause_status</code></td><td>Required field</td></tr><tr><td>Invalid <code>comparison_operator</code></td><td><code>EQUAL</code>, <code>NOT_EQUAL</code>, <code>GREATER_THAN</code>, <code>GREATER_THAN_OR_EQUAL</code>, <code>LESS_THAN</code>, <code>LESS_THAN_OR_EQUAL</code></td></tr></tbody></table><h3 id="volume-permissions" tabindex="-1">Volume Permissions <a class="header-anchor" href="#volume-permissions" aria-label="Permalink to &quot;Volume Permissions&quot;">​</a></h3><p>Volumes use <code>grants:</code> not <code>permissions:</code>. CatalystOps errors if <code>permissions:</code> is found on a volume resource.</p><h3 id="mutual-exclusions" tabindex="-1">Mutual Exclusions <a class="header-anchor" href="#mutual-exclusions" aria-label="Permalink to &quot;Mutual Exclusions&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Conflict</th><th>Error</th></tr></thead><tbody><tr><td><code>schedule:</code> + <code>continuous:</code> on same job</td><td>Error</td></tr><tr><td><code>job_cluster_key:</code> + <code>existing_cluster_id:</code> on same task</td><td>Error</td></tr></tbody></table><h3 id="cluster-environment-checks" tabindex="-1">Cluster / Environment Checks <a class="header-anchor" href="#cluster-environment-checks" aria-label="Permalink to &quot;Cluster / Environment Checks&quot;">​</a></h3><ul><li><code>data_security_mode: NONE</code> when a production target exists → Warning</li><li><code>data_security_mode: SINGLE_USER</code> without <code>single_user_name</code> → Warning</li><li><code>spark_version</code> format check (must match <code>14.3.x</code> / <code>14.3.x-scala2.12</code> pattern)</li><li><code>num_workers</code> must be ≥ 0</li><li><code>autotermination_minutes</code> must be 10–10000</li><li><code>max_concurrent_runs</code> must be 0–1000</li><li><code>environments[].spec.client</code> is required — use <code>&quot;4&quot;</code> for current serverless</li></ul><h3 id="deprecated-fields" tabindex="-1">Deprecated Fields <a class="header-anchor" href="#deprecated-fields" aria-label="Permalink to &quot;Deprecated Fields&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Field</th><th>Replacement</th></tr></thead><tbody><tr><td><code>photon: true</code></td><td><code>runtime_engine: PHOTON</code></td></tr><tr><td><code>jar_uri</code> in <code>spark_python_task</code></td><td>Use <code>libraries:</code> with <code>whl:</code> or <code>jar:</code></td></tr></tbody></table><h3 id="file-existence-checks" tabindex="-1">File Existence Checks <a class="header-anchor" href="#file-existence-checks" aria-label="Permalink to &quot;File Existence Checks&quot;">​</a></h3><ul><li><code>spark_python_task.python_file</code> — resolved relative to the YAML file&#39;s directory</li><li><code>notebook_task.notebook_path</code> — local paths only (not <code>/Workspace/...</code>) are checked</li></ul><h2 id="bundle-target-in-connection-wizard" tabindex="-1">Bundle Target in Connection Wizard <a class="header-anchor" href="#bundle-target-in-connection-wizard" aria-label="Permalink to &quot;Bundle Target in Connection Wizard&quot;">​</a></h2><p>When <code>databricks.yml</code> is present, <strong>CatalystOps: Configure Databricks Connection</strong> shows a <strong>Use Bundle Target</strong> option. Select a target (dev / prod / staging) and the wizard pre-fills the workspace host from the YAML — no URL to type manually.</p><h2 id="mcp-tool" tabindex="-1">MCP Tool <a class="header-anchor" href="#mcp-tool" aria-label="Permalink to &quot;MCP Tool&quot;">​</a></h2><p>The <code>list_bundle_tasks</code> MCP tool exposes bundle tasks to Claude, Copilot, and other MCP-compatible clients:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>You: What tasks are defined in my bundle?</span></span>
<span class="line"><span>Claude: ↳ calling list_bundle_tasks…</span></span>
<span class="line"><span>        Found 3 tasks in 2 jobs:</span></span>
<span class="line"><span>        - daily_etl → extract_data (spark_python_task): src/extract.py</span></span>
<span class="line"><span>        - daily_etl → transform (spark_python_task): src/transform.py</span></span>
<span class="line"><span>        - scoring_job → score (notebook_task): src/score.py</span></span></code></pre></div>`,30)])])}const _=t(c,[["render",s]]);export{p as __pageData,_ as default};
